def _legacy_mergeOrderings(orderings):
    # Create a dictionary to store item positions
    item_positions = {}

    # Create a dictionary to store items that must come before others
    dependencies = {}

    # Process each ordering list
    for ordering in orderings:
        # Track position of each item in this ordering
        for i, item in enumerate(ordering):
            if item not in item_positions:
                item_positions[item] = []
            item_positions[item].append(i)

            # Add dependencies - each item must come after previous items
            if i > 0:
                prev = ordering[i-1]
                if prev not in dependencies:
                    dependencies[prev] = set()
                dependencies[prev].add(item)

    # Get all unique items
    all_items = set()
    for ordering in orderings:
        all_items.update(ordering)

    # Build result list
    result = []
    used = set()

    while len(result) < len(all_items):
        # Find items with no remaining dependencies
        available = set()
        for item in all_items:
            if item not in used:
                has_deps = False
                for deps in dependencies.values():
                    if item in deps:
                        has_deps = True
                        break
                if not has_deps:
                    available.add(item)

        if not available:
            raise ValueError("Circular dependency detected")

        # Add the first available item
        item = next(iter(available))
        result.append(item)
        used.add(item)

        # Remove this item from dependencies
        if item in dependencies:
            del dependencies[item]

    return result

def minimalBases(classes):
    """
    आधार कक्षाओं (base classes) की सूची को उसके क्रमबद्ध न्यूनतम समकक्ष (ordered minimum equivalent) में घटाएं।
    """
    if not classes:
        return []

    # Remove duplicates while preserving order
    seen = set()
    unique_classes = []
    for cls in classes:
        if cls not in seen:
            seen.add(cls)
            unique_classes.append(cls)

    # Remove redundant base classes
    minimal = []
    for i, cls in enumerate(unique_classes):
        is_redundant = False
        for j in range(i + 1, len(unique_classes)):
            # Check if cls is a base class of any later class
            if issubclass(unique_classes[j], cls):
                is_redundant = True
                break
        if not is_redundant:
            minimal.append(cls)

    return minimal

