def _update_context(self, context):
    # Get all field names in the graph
    field_names = self.get_field_names()

    # Initialize error context if not present
    if not hasattr(context, 'error'):
        context.error = {}

    # Map coordinate names to x,y,z
    coord_names = ['x', 'y', 'z']

    # Look for error fields and update context
    for field in field_names:
        # Check if field name contains 'error'
        if 'error' in field.lower():
            # Extract base name before '_error'
            base = field.split('_error')[0].lower()

            # Map to x,y,z if possible
            for i, coord in enumerate(coord_names):
                if base == coord:
                    base = coord
                    break

            # Get index of error field
            idx = field_names.index(field)

            # Add to context.error
            if base not in context.error:
                context.error[base] = {}
            context.error[base]['index'] = idx

    # Preserve existing values in context.value
    if hasattr(context, 'value'):
        pass

def is_fill_request_seq(seq):
    # Check if seq is None or empty
    if not seq:
        return False

    # Import needed for isinstance check
    from typing import Sequence
    from fillrequest import FillRequest
    from source import Source

    # If seq is a single FillRequest, return True
    if isinstance(seq, FillRequest):
        return True

    # If seq is a Source sequence, return False
    if isinstance(seq, Source):
        return False

    # Check if seq is a sequence and contains at least one FillRequest
    if isinstance(seq, Sequence):
        return any(isinstance(item, FillRequest) for item in seq)

    # If none of above conditions met, return False
    return False

