def difference(d1, d2, level=-1):
    """
    Returns a dictionary containing items from d1 that are not in d2.

    Args:
        d1: First dictionary
        d2: Second dictionary 
        level: Maximum recursion depth. Set to -1 for infinite recursion.

    Returns:
        Dictionary containing items from d1 that are not in d2
    """
    result = {}

    # Handle base case where level is 0
    if level == 0:
        return d1.copy()

    for key in d1:
        # If key not in d2, include it in result
        if key not in d2:
            result[key] = d1[key]

        # If key in both d1 and d2
        elif isinstance(d1[key], dict) and isinstance(d2[key], dict):
            # Recurse if both values are dictionaries and level allows
            if level != 1:
                diff = difference(d1[key], d2[key], level-1 if level > 0 else -1)
                if diff:
                    result[key] = diff

        # If values are different, include in result for level 1+
        elif d1[key] != d2[key]:
            result[key] = d1[key]

    return result

def _validate_labels(labels):
    import re
    from typing import Dict, Any, List

    # Regular expressions for validation
    KEY_REGEX = r'^[a-zA-Z][a-zA-Z0-9_-]*$'
    VALUE_REGEX = r'^[a-zA-Z0-9_-]+$'

    errors: List[Dict[str, str]] = []

    # Validate each key-value pair
    for key, value in labels.items():
        # Validate key type
        if not isinstance(key, str):
            errors.append({
                str(key): 'expected string or bytes-like object'
            })
            continue

        # Validate key format
        if not re.match(KEY_REGEX, key):
            errors.append({
                key: f"Label key '{key}' does not match the regex {KEY_REGEX}"
            })

        # Validate value type
        if not isinstance(value, str):
            errors.append({
                str(value): 'expected string or bytes-like object'
            })
            continue

        # Validate value format
        if not re.match(VALUE_REGEX, value):
            errors.append({
                value: f"Label value '{value}' does not match the regex {VALUE_REGEX}"
            })

    # Raise ValidationError if any errors found
    if errors:
        raise ValidationError(errors)

class ValidationError(Exception):
    def __init__(self, messages):
        self.messages = messages
        super().__init__(str(messages))

def validate_key(key):
    import re
    from django.core.exceptions import ValidationError

    # Regular expression pattern for key validation
    # Allows alphanumeric characters and underscores, minimum 1 character
    pattern = r'^[a-zA-Z0-9_]+$'

    if not isinstance(key, str):
        raise ValidationError("Key must be a string")

    if not key:
        raise ValidationError("Key cannot be empty")

    if not re.match(pattern, key):
        raise ValidationError("Key can only contain letters, numbers and underscores")

    return True

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    # Initialize empty dictionary for observer schema
    observer_schema = {}

    # Iterate through key-value pairs in manifest dictionary
    for key, value in manifest_dict.items():

        # Handle nested dictionaries recursively
        if isinstance(value, dict):
            observer_schema[key] = generate_default_observer_schema_dict(value)

        # Handle lists by calling generate_default_observer_schema_list
        elif isinstance(value, list):
            from .utils import generate_default_observer_schema_list
            observer_schema[key] = generate_default_observer_schema_list(value)

        # For first level dictionary, copy identifying fields
        elif first_level and key in ['apiVersion', 'kind', 'metadata']:
            observer_schema[key] = value

        # For all other values, set to None
        else:
            observer_schema[key] = None

    return observer_schema

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    # Handle empty cases
    if not observer_schema or not response:
        return

    # Ensure last_applied_manifest has enough elements
    while len(last_applied_manifest) < len(response):
        last_applied_manifest.append({} if isinstance(response[0], dict) else None)

    # Iterate through response items
    for i, resp_item in enumerate(response):
        if i >= len(observer_schema):
            break

        schema_item = observer_schema[i]

        # Handle dict items recursively
        if isinstance(resp_item, dict) and isinstance(schema_item, dict):
            if not isinstance(last_applied_manifest[i], dict):
                last_applied_manifest[i] = {}
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[i],
                schema_item,
                resp_item
            )

        # Handle list items recursively    
        elif isinstance(resp_item, list) and isinstance(schema_item, list):
            if not isinstance(last_applied_manifest[i], list):
                last_applied_manifest[i] = []
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[i],
                schema_item,
                resp_item
            )

        # Handle primitive values
        else:
            last_applied_manifest[i] = resp_item

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    # Iterate through all fields in observer schema
    for field, value in observer_schema.items():
        # Skip if field doesn't exist in response
        if field not in response:
            continue

        # Initialize field in last_applied_manifest if it doesn't exist
        if field not in last_applied_manifest:
            if isinstance(response[field], dict):
                last_applied_manifest[field] = {}
            elif isinstance(response[field], list):
                last_applied_manifest[field] = []
            else:
                last_applied_manifest[field] = response[field]
                continue

        # Recursively update nested dictionaries
        if isinstance(value, dict) and isinstance(response[field], dict):
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[field], value, response[field]
            )
        # Update lists
        elif isinstance(value, list) and isinstance(response[field], list):
            if len(value) > 0 and isinstance(value[0], dict):
                # Handle list of dictionaries
                if len(last_applied_manifest[field]) < len(response[field]):
                    last_applied_manifest[field].extend(
                        [{}] * (len(response[field]) - len(last_applied_manifest[field]))
                    )
                for i in range(len(response[field])):
                    update_last_applied_manifest_dict_from_resp(
                        last_applied_manifest[field][i], value[0], response[field][i]
                    )
            else:
                # Handle simple lists
                last_applied_manifest[field] = response[field]
        else:
            # Update simple values
            last_applied_manifest[field] = response[field]

def generate_default_observer_schema(app):
    default_schema = {}

    # Iterate through each resource in the application manifest
    for resource in app.spec.manifest:
        # Skip if resource already has custom observer schema defined
        if resource.get('observer_schema'):
            continue

        # Get resource kind and API version
        kind = resource.get('kind', '')
        api_version = resource.get('apiVersion', '')

        # Generate default schema based on resource kind
        if kind.lower() == 'deployment':
            default_schema[f"{api_version}/{kind}"] = {
                'ready': '$.status.readyReplicas == $.spec.replicas'
            }

        elif kind.lower() == 'statefulset':
            default_schema[f"{api_version}/{kind}"] = {
                'ready': '$.status.readyReplicas == $.spec.replicas'
            }

        elif kind.lower() == 'daemonset':
            default_schema[f"{api_version}/{kind}"] = {
                'ready': '$.status.numberReady == $.status.desiredNumberScheduled'
            }

        elif kind.lower() == 'pod':
            default_schema[f"{api_version}/{kind}"] = {
                'ready': "$.status.phase in ['Running', 'Succeeded']"
            }

        elif kind.lower() == 'service':
            default_schema[f"{api_version}/{kind}"] = {
                'ready': 'true'
            }

        elif kind.lower() == 'persistentvolumeclaim':
            default_schema[f"{api_version}/{kind}"] = {
                'ready': "$.status.phase == 'Bound'"
            }

        else:
            # Default schema for other resource types
            default_schema[f"{api_version}/{kind}"] = {
                'ready': 'true'
            }

    return default_schema

def format(
    self,
    sql: AnyStr,
    params: Union[Dict[Union[str, int], Any], Sequence[Any]],
) -> Tuple[AnyStr, Union[Dict[Union[str, int], Any], Sequence[Any]]]:

    # Handle empty params case
    if not params:
        return sql, params

    # Convert named parameters style
    if isinstance(params, dict):
        new_params = {}
        counter = 1

        # Replace named parameters with positional parameters
        for key, value in params.items():
            placeholder = f'${counter}'
            if isinstance(sql, str):
                sql = sql.replace(f':{key}', placeholder)
                sql = sql.replace(f'%({key})s', placeholder)
            else:  # bytes
                sql = sql.replace(f':{key}'.encode(), placeholder.encode())
                sql = sql.replace(f'%({key})s'.encode(), placeholder.encode())
            new_params[counter] = value
            counter += 1

        return sql, new_params

    # Convert positional parameters style 
    else:
        new_params = {}
        for i, value in enumerate(params, 1):
            if isinstance(sql, str):
                sql = sql.replace('?', f'${i}', 1)
                sql = sql.replace('%s', f'${i}', 1)
            else:  # bytes
                sql = sql.replace(b'?', f'${i}'.encode(), 1)
                sql = sql.replace(b'%s', f'${i}'.encode(), 1)
            new_params[i] = value

        return sql, new_params

def formatmany(
        self,
        sql: AnyStr,
        many_params: Union[Iterable[Dict[Union[str, int], Any]], Iterable[Sequence[Any]]],
) -> Tuple[AnyStr, Union[List[Dict[Union[str, int], Any]], List[Sequence[Any]]]]:

    # Convert params to list for processing
    params_list = list(many_params)

    if not params_list:
        return sql, []

    # Get first param to determine type
    first_param = params_list[0]

    # Check if named parameters (dict) or ordinal parameters (sequence)
    is_named = isinstance(first_param, dict)

    # Convert SQL and params based on parameter style
    if is_named:
        # For named parameters
        # Replace :name or %(name)s with ? or $n based on out_style
        param_names = list(first_param.keys())
        converted_sql = sql

        if self.in_style in [':named', 'named']:
            for name in param_names:
                converted_sql = converted_sql.replace(f':{name}', 
                    self.out_style_placeholder(param_names.index(name)))
        elif self.in_style == 'pyformat':
            for name in param_names:
                converted_sql = converted_sql.replace(f'%({name})s',
                    self.out_style_placeholder(param_names.index(name)))

        # Convert parameters to list in correct order
        converted_params = []
        for params in params_list:
            param_values = [params[name] for name in param_names]
            if self.out_style == 'named':
                # Convert back to dict for named out style
                converted_params.append(dict(zip(param_names, param_values)))
            else:
                converted_params.append(param_values)

    else:
        # For ordinal parameters
        # Replace %s with ? or $n based on out_style
        param_count = len(first_param)
        converted_sql = sql

        if self.in_style == 'format':
            for i in range(param_count):
                converted_sql = converted_sql.replace('%s',
                    self.out_style_placeholder(i), 1)

        # Parameters remain as sequences
        converted_params = params_list
        if self.out_style == 'named':
            # Convert sequences to dicts for named out style
            converted_params = [
                dict(enumerate(params)) for params in params_list
            ]

    return converted_sql, converted_params

def validate(self, path):
    try:
        # Check if path exists
        if not os.path.exists(path):
            return False

        # Verify required OCFL structure elements
        required_files = ['0=ocfl_object_1.0', 'inventory.json']
        for file in required_files:
            if not os.path.exists(os.path.join(path, file)):
                return False

        # Load and validate inventory
        with open(os.path.join(path, 'inventory.json')) as f:
            inventory = json.load(f)

        # Check required inventory fields
        required_fields = ['id', 'type', 'digestAlgorithm', 'versions']
        for field in required_fields:
            if field not in inventory:
                return False

        # Validate versions
        if not inventory['versions']:
            return False

        # Verify version directories exist
        for version in inventory['versions']:
            version_path = os.path.join(path, 'v' + str(version))
            if not os.path.exists(version_path):
                return False

        # If we get here, object is valid
        return True

    except Exception:
        return False

def status_str(self, prefix=''):
    """
    सत्यापन लॉग (validation log) का स्ट्रिंग प्रतिनिधित्व लौटाएं, वैकल्पिक प्रीफिक्स के साथ।
    """
    result = []
    for entry in self.log:
        if isinstance(entry, str):
            result.append(prefix + entry)
        else:
            result.append(prefix + str(entry))
    return '\n'.join(result)

def validate(self, inventory, extract_spec_version=False):
    """
    दिए गए इन्वेंटरी को सत्यापित करें।

    यदि `extract_spec_version` का मान `True` है, तो यह `type` मान को देखकर 
    स्पेसिफिकेशन वर्जन निर्धारित करेगा। यदि `type` मान मौजूद नहीं है या यह 
    मान्य नहीं है, तो अन्य परीक्षण `self.spec_version` में दिए गए वर्जन के 
    आधार पर किए जाएंगे।
    """
    if not isinstance(inventory, dict):
        raise ValueError("Inventory must be a dictionary")

    if extract_spec_version:
        if 'type' in inventory:
            type_value = inventory['type']
            if isinstance(type_value, str):
                # Extract version from type value
                if type_value.startswith('v'):
                    try:
                        version = float(type_value[1:])
                        self.spec_version = version
                    except ValueError:
                        pass # Use default spec_version if conversion fails

    # Validate required fields based on spec_version
    required_fields = ['id', 'name']
    if self.spec_version >= 2.0:
        required_fields.extend(['description', 'category'])

    for field in required_fields:
        if field not in inventory:
            raise ValueError(f"Missing required field: {field}")
        if not inventory[field]:  # Check for empty values
            raise ValueError(f"Field '{field}' cannot be empty")

    # Validate data types
    if not isinstance(inventory['id'], (str, int)):
        raise ValueError("'id' must be string or integer")
    if not isinstance(inventory['name'], str):
        raise ValueError("'name' must be string")

    if self.spec_version >= 2.0:
        if not isinstance(inventory['description'], str):
            raise ValueError("'description' must be string")
        if not isinstance(inventory['category'], str):
            raise ValueError("'category' must be string")

    # Optional field validations
    if 'quantity' in inventory:
        if not isinstance(inventory['quantity'], (int, float)):
            raise ValueError("'quantity' must be numeric")
        if inventory['quantity'] < 0:
            raise ValueError("'quantity' cannot be negative")

    return True

def validate_as_prior_version(self, prior):
    """
    वर्तमान इन्वेंटरी ऑब्जेक्ट के लिए यह जांचें कि prior एक मान्य पूर्व संस्करण है।

    इनपुट वैरिएबल प्रायर को भी एक इन्वेंटरी वैलिडेटर ऑब्जेक्ट माना जाता है और माना जाता है कि स्व और प्रायर दोनों इन्वेंटरी को आंतरिक संगतता के लिए जाँच लिया गया है।
    """
    # Check that prior version timestamp is before current version
    if prior.timestamp >= self.timestamp:
        return False

    # Check that all items in prior version exist in current version
    for item_id in prior.inventory:
        if item_id not in self.inventory:
            return False

        # Check that quantities only increase
        if prior.inventory[item_id] > self.inventory[item_id]:
            return False

    return True

def get_logical_path_map(inventory, version):
    logical_path_map = {}

    # Get all content files for this version and later versions
    content_files = set()
    for v in inventory.versions:
        if v >= version:
            content_files.update(inventory.get_content_files(v))

    # Build mapping of logical paths to content files
    for logical_path in inventory.get_logical_paths(version):
        matching_files = set()
        for content_file in content_files:
            if inventory.matches_logical_path(logical_path, content_file, version):
                matching_files.add(content_file)
        if matching_files:
            logical_path_map[logical_path] = matching_files

    return logical_path_map

def validate_fixity(self, fixity, manifest_files):
    """
    इन्वेंटरी में फिक्सिटी ब्लॉक को सत्यापित करें।
    फिक्सिटी ब्लॉक की संरचना की जांच करें और सुनिश्चित करें कि केवल वे फाइलें
    जो मैनिफेस्ट में सूचीबद्ध हैं, वही संदर्भित की गई हैं।
    """
    # Check if fixity block is a dictionary
    if not isinstance(fixity, dict):
        return False

    # Check if all required keys exist in fixity block
    required_keys = ['message_digest_algorithm', 'message_digests']
    if not all(key in fixity for key in required_keys):
        return False

    # Check if message_digests is a list
    if not isinstance(fixity['message_digests'], list):
        return False

    # Check each message digest entry
    for digest in fixity['message_digests']:
        # Verify digest structure
        if not isinstance(digest, dict):
            return False

        if 'file_path' not in digest or 'hash' not in digest:
            return False

        # Verify file exists in manifest
        if digest['file_path'] not in manifest_files:
            return False

        # Verify hash is a string
        if not isinstance(digest['hash'], str):
            return False

    return True

def add_rendition(self, lang, file_path):
    """
    Adds a rendition file path for a specific language to the renditions dictionary.

    Args:
        lang (str): Language code for the rendition (e.g. 'en', 'es')
        file_path (str): Path to the rendition file

    Returns:
        None

    Example:
    {
        "original": "artigo02.pdf",
        "en": "artigo02-en.pdf",
    }
    """
    if not hasattr(self, 'renditions'):
        self.renditions = {}

    if lang == 'original':
        self.renditions['original'] = file_path
    else:
        self.renditions[lang] = file_path

def fix_namespace_prefix_w(content):
    # Replace 'w:st="' with 'w-st="' in the content
    return content.replace('w:st="', 'w-st="')

def match_pubdate(node, pubdate_xpaths):
    """
    `pubdate_xpaths` सूची में पहला मेलित मान (match) लौटाता है।
    """
    for xpath in pubdate_xpaths:
        try:
            # Try to find matching element using xpath
            match = node.xpath(xpath)
            if match:
                # Return first matching value if found
                return match[0]
        except:
            # Skip any xpath that causes errors
            continue

    # Return None if no matches found
    return None

def _extract_number_and_supplment_from_issue_element(issue):
    """
    समस्या (issue) की सामग्री से number और suppl के संभावित मानों को निकालें।
    """
    number = None
    suppl = None

    if issue:
        # Remove any whitespace
        issue = issue.strip()

        # Check if issue contains supplement indicator
        if 'suppl' in issue.lower():
            parts = issue.lower().split('suppl')
            if parts[0]:
                number = parts[0].strip()
            if len(parts) > 1 and parts[1]:
                suppl = parts[1].strip()
        else:
            # If no supplement, treat entire string as number
            number = issue

        # Convert number to integer if possible
        try:
            number = int(number) if number else None
        except (ValueError, TypeError):
            number = number

        # Clean up supplement value
        if suppl:
            suppl = suppl.strip(' .')
            if suppl.startswith('.'):
                suppl = suppl[1:]

    return number, suppl

def pretty(self, indent=0, debug=False):
    """
    स्वयं का एक सुंदर स्वरूपित प्रतिनिधित्व लौटाएँ।
    """
    # Create indentation string
    indent_str = " " * indent

    # Get the string representation of the object
    if debug:
        # Include more detailed debug information
        result = f"{indent_str}{self.__class__.__name__}:\n"
        for attr, value in self.__dict__.items():
            result += f"{indent_str}  {attr}: {value}\n"
        return result.rstrip()
    else:
        # Basic pretty formatting
        return f"{indent_str}{str(self)}"

def absorb(self, args):
    # Create copy of input list to avoid modifying original
    result = args.copy()

    # Keep track if any changes were made in a pass
    changed = True
    while changed:
        changed = False

        # Check each pair of expressions
        for i in range(len(result)):
            for j in range(len(result)):
                if i == j:
                    continue

                # Get expressions to compare
                expr1 = result[i]
                expr2 = result[j]

                # Check absorption cases
                # A & (A | B) = A
                if isinstance(expr1, str) and isinstance(expr2, tuple):
                    if expr2[1] == '|' and expr1 in expr2[0]:
                        if expr1 not in result:
                            result.append(expr1)
                            changed = True

                # A | (A & B) = A            
                if isinstance(expr1, str) and isinstance(expr2, tuple):
                    if expr2[1] == '&' and expr1 in expr2[0]:
                        if expr1 not in result:
                            result.append(expr1)
                            changed = True

                # Negative absorption
                # A & (~A | B) = A & B
                if isinstance(expr1, str) and isinstance(expr2, tuple):
                    if expr2[1] == '|' and f'~{expr1}' in expr2[0]:
                        new_expr = (expr1, '&', expr2[0][1])
                        if new_expr not in result:
                            result.append(new_expr)
                            changed = True

                # A | (~A & B) = A | B
                if isinstance(expr1, str) and isinstance(expr2, tuple):
                    if expr2[1] == '&' and f'~{expr1}' in expr2[0]:
                        new_expr = (expr1, '|', expr2[0][1]) 
                        if new_expr not in result:
                            result.append(new_expr)
                            changed = True

        # Remove redundant expressions
        result = list(set(result))

    return result

def on(self, hook):
    def decorator(handler):
        if hook not in self._registry:
            self._registry[hook] = []
        self._registry[hook].append(handler)
        return handler
    return decorator

def tzname_in_python2(namefunc):
    """
    Python 2 में यूनिकोड आउटपुट को बाइटस्ट्रिंग्स में बदलें।

    tzname() API ने Python 3 में बदलाव किया। पहले यह बाइट्स लौटाता था, 
    लेकिन इसे यूनिकोड स्ट्रिंग्स में बदल दिया गया।
    """
    def adjust_encoding(*args, **kwargs):
        name = namefunc(*args, **kwargs)
        if name is not None:
            if isinstance(name, str):
                return name.encode('ASCII')
            return name
    return adjust_encoding

def get_versions():
    """
    संस्करण जानकारी प्राप्त करें या यदि ऐसा करने में असमर्थ हैं तो डिफ़ॉल्ट मान लौटाएं।
    """
    try:
        import pkg_resources
        import platform
        import sys

        versions = {
            'python': sys.version.split()[0],
            'platform': platform.platform(),
            'packages': {
                dist.key: dist.version
                for dist in pkg_resources.working_set
            }
        }
        return versions

    except Exception:
        # Return default values if unable to get version info
        return {
            'python': 'unknown',
            'platform': 'unknown',
            'packages': {}
        }

def render(pieces, style):
    """
    दिए गए संस्करण टुकड़ों को निर्दिष्ट शैली में प्रस्तुत करें।
    """
    if not pieces:
        return ""

    if style == "plain":
        return "".join(pieces)
    elif style == "html":
        return "<div>" + "".join(pieces) + "</div>"
    elif style == "markdown":
        return "_" + "".join(pieces) + "_"
    else:
        return "".join(pieces)

def plus_or_dot(pieces):
    if "+" in pieces:
        return "."
    return "+"

def run_command(commands, args, cwd=None, verbose=False, hide_stderr=False, env=None):
    """
    दिए गए कमांड(s) को चलाएं।
    """
    import subprocess
    import sys

    if isinstance(commands, str):
        commands = [commands]

    for cmd in commands:
        cmd_list = [cmd]
        if args:
            if isinstance(args, str):
                cmd_list.append(args)
            else:
                cmd_list.extend(args)

        if verbose:
            print('Running:', ' '.join(cmd_list))

        try:
            stderr = subprocess.DEVNULL if hide_stderr else None
            process = subprocess.Popen(
                cmd_list,
                stdout=subprocess.PIPE,
                stderr=stderr,
                cwd=cwd,
                env=env,
                universal_newlines=True
            )

            output, error = process.communicate()

            if process.returncode != 0:
                print(f"Error executing command: {' '.join(cmd_list)}")
                if error and not hide_stderr:
                    print(f"Error output: {error}")
                sys.exit(process.returncode)

            if verbose and output:
                print(output)

            return output.strip() if output else None

        except Exception as e:
            print(f"Exception occurred while executing command: {' '.join(cmd_list)}")
            print(f"Error: {str(e)}")
            sys.exit(1)

def validate_hierarchy(self, validate_objects=True, check_digests=True, show_warnings=False):
    """
    स्टोरेज रूट हाइरार्की को मान्य करें।

    रिटर्न करता है:
        num_objects - जांचे गए ऑब्जेक्ट्स की संख्या
        good_objects - जांचे गए ऑब्जेक्ट्स की संख्या जो मान्य पाए गए
    """
    num_objects = 0
    good_objects = 0

    # Recursively walk through all directories
    for root, dirs, files in self.walk():
        for file in files:
            num_objects += 1

            # Get full path
            filepath = os.path.join(root, file)

            try:
                # Validate object if requested
                if validate_objects:
                    obj = self.get_object(filepath)
                    if obj is None:
                        if show_warnings:
                            print(f"Warning: Could not load object at {filepath}")
                        continue

                # Check digest if requested        
                if check_digests:
                    stored_digest = self.get_digest(filepath)
                    computed_digest = self.compute_digest(filepath)

                    if stored_digest != computed_digest:
                        if show_warnings:
                            print(f"Warning: Digest mismatch for {filepath}")
                        continue

                good_objects += 1

            except Exception as e:
                if show_warnings:
                    print(f"Warning: Error validating {filepath}: {str(e)}")
                continue

    return num_objects, good_objects

def next_version(version):
    # Split version into parts by dot
    parts = version.split('.')

    # Convert parts to integers
    nums = [int(x) for x in parts]

    # Start from rightmost digit
    i = len(nums) - 1

    while i >= 0:
        # If current digit is 9, set to 0 and continue to next digit
        if nums[i] == 9:
            nums[i] = 0
            i -= 1
        else:
            # Otherwise increment current digit and break
            nums[i] += 1
            break

    # If we ran out of digits to increment, add a 1 at the start
    if i < 0:
        nums.insert(0, 1)

    # Convert back to strings preserving original zero padding
    result = []
    for i in range(len(nums)):
        # Get original part to check if it had zero padding
        orig = parts[i] if i < len(parts) else ''
        if orig.startswith('0') and len(orig) > 1:
            # Preserve zero padding
            result.append(str(nums[i]).zfill(len(orig)))
        else:
            result.append(str(nums[i]))

    return '.'.join(result)

def find_path_type(path):
    import os
    import glob

    # Check if path exists
    if not os.path.exists(path):
        return "Path does not exist"

    # If path is a file
    if os.path.isfile(path):
        return "file"

    # If path is a directory
    if os.path.isdir(path):
        # Look for namaste files matching 0=*
        namaste_files = glob.glob(os.path.join(path, "0=*"))

        if not namaste_files:
            return "No namaste files found"

        # Read first namaste file content
        try:
            with open(namaste_files[0], 'r') as f:
                content = f.read().strip()

            # Check content for root vs object
            if content == "ocfl_1.0":
                return "root"
            elif content == "ocfl_object_1.0":
                return "object"
            else:
                return f"Unknown namaste file content: {content}"

        except Exception as e:
            return f"Error reading namaste file: {str(e)}"

    return "Unknown path type"

def amend_bzparams(self, params, bug_ids):
    """
    बगज़िला पैरामीटर्स को संशोधित करें
    """
    if not bug_ids:
        return params

    if isinstance(bug_ids, (str, int)):
        bug_ids = [str(bug_ids)]
    else:
        bug_ids = [str(bug_id) for bug_id in bug_ids]

    if 'bug_id' in params:
        params['bug_id'].extend(bug_ids)
    else:
        params['bug_id'] = bug_ids

    return params

def parse_arguments(*arguments):
    import argparse

    # Create ArgumentParser instance
    parser = argparse.ArgumentParser(description='Command line argument parser')

    # Add arguments to parser
    for arg in arguments:
        if isinstance(arg, str):
            parser.add_argument(arg)
        elif isinstance(arg, tuple):
            # Handle tuple arguments with name and help text
            if len(arg) == 2:
                parser.add_argument(arg[0], help=arg[1])
            # Handle tuple arguments with name, type and help text
            elif len(arg) == 3:
                parser.add_argument(arg[0], type=arg[1], help=arg[2])

    # Parse arguments
    args = parser.parse_args()

    return args

def parse_arguments(*arguments):
    import argparse

    # Create ArgumentParser instance
    parser = argparse.ArgumentParser(description='Command line argument parser')

    # Add arguments to parser
    for arg in arguments:
        if isinstance(arg, str):
            parser.add_argument(arg)
        elif isinstance(arg, tuple):
            # Handle tuple arguments with name and help text
